1	import { useEffect, useState } from 'react'
2	import { Navigate, Outlet, useNavigate, useLocation } from 'react-router-dom'
3	import {
4	  contractorAuthStorage,
5	  CONTRACTOR_TOKEN_CLEARED_EVENT,
6	} from './contractorAuth'
7	
8	const ContractorGuard = () => {
9	  const [token, setToken] = useState(() => {
10	    const t = contractorAuthStorage.getToken()
11	    return t
12	  })
13	  const { pathname } = useLocation()
14	  const navigate = useNavigate()
15	
16	  useEffect(() => {
17	    if (pathname === '/contractor') {
18	      navigate('/contractor/list', { replace: true })
19	    }
20	  }, [pathname])
21	
22	  useEffect(() => {
23	    const handleTokenCleared = () => {
24	      setToken(null)
25	    }
26	    window.addEventListener(CONTRACTOR_TOKEN_CLEARED_EVENT, handleTokenCleared)
27	    return () => {
28	      window.removeEventListener(CONTRACTOR_TOKEN_CLEARED_EVENT, handleTokenCleared)
29	    }
30	  }, [])
31	
32	  if (!token) {
33	    return <Navigate to='/contractor-login' replace />
34	  }
35	
36	  return <Outlet />
37	}
38	
39	export default ContractorGuard
40

